import{_ as t,o as e,c as s,ae as i}from"./chunks/framework.CC-i3qbO.js";const u=JSON.parse('{"title":"Q16: 如何设计一个可扩展的微服务架构？","description":"","frontmatter":{},"headers":[],"relativePath":"04-design/q16-microservice-architecture.md","filePath":"04-design/q16-microservice-architecture.md"}'),n={name:"04-design/q16-microservice-architecture.md"};function l(r,a,d,o,c,h){return e(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="q16-如何设计一个可扩展的微服务架构" tabindex="-1">Q16: 如何设计一个可扩展的微服务架构？ <a class="header-anchor" href="#q16-如何设计一个可扩展的微服务架构" aria-label="Permalink to &quot;Q16: 如何设计一个可扩展的微服务架构？&quot;">​</a></h1><h2 id="架构设计原则" tabindex="-1">架构设计原则 <a class="header-anchor" href="#架构设计原则" aria-label="Permalink to &quot;架构设计原则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原则</th><th>说明</th></tr></thead><tbody><tr><td>单一职责</td><td>每个服务专注单一业务域</td></tr><tr><td>高内聚低耦合</td><td>服务内部紧耦合，服务间松耦合</td></tr><tr><td>服务自治</td><td>独立部署、测试、升级</td></tr><tr><td>可观测</td><td>日志、监控、链路追踪</td></tr><tr><td>基础设施自动化</td><td>CI/CD、容器化、自动扩缩容</td></tr></tbody></table><h2 id="领域驱动设计-ddd" tabindex="-1">领域驱动设计（DDD） <a class="header-anchor" href="#领域驱动设计-ddd" aria-label="Permalink to &quot;领域驱动设计（DDD）&quot;">​</a></h2><h3 id="ddd分层架构" tabindex="-1">DDD分层架构 <a class="header-anchor" href="#ddd分层架构" aria-label="Permalink to &quot;DDD分层架构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>API Gateway              ← 网关层</span></span>
<span class="line"><span>Application Service     ← 应用层（编排、事务）</span></span>
<span class="line"><span>Domain Service / Entity ← 领域层（核心业务逻辑）</span></span>
<span class="line"><span>Repository / DAO        ← 基础设施层（持久化）</span></span></code></pre></div><h3 id="ddd战略建模" tabindex="-1">DDD战略建模 <a class="header-anchor" href="#ddd战略建模" aria-label="Permalink to &quot;DDD战略建模&quot;">​</a></h3><ul><li><strong>子域（SubDomain）</strong>：业务领域划分</li><li><strong>限界上下文（Bounded Context）</strong>：服务边界</li><li><strong>实体（Entity）</strong>：有唯一标识的对象</li><li><strong>值对象（Value Object）</strong>：无标识的属性集合</li></ul><h2 id="服务拆分策略" tabindex="-1">服务拆分策略 <a class="header-anchor" href="#服务拆分策略" aria-label="Permalink to &quot;服务拆分策略&quot;">​</a></h2><h3 id="按业务能力拆分" tabindex="-1">按业务能力拆分 <a class="header-anchor" href="#按业务能力拆分" aria-label="Permalink to &quot;按业务能力拆分&quot;">​</a></h3><ul><li>订单服务：订单创建、查询、取消</li><li>支付服务：支付、退款</li><li>库存服务：库存查询、扣减</li><li>用户服务：注册、登录、权限</li></ul><h3 id="拆分粒度原则" tabindex="-1">拆分粒度原则 <a class="header-anchor" href="#拆分粒度原则" aria-label="Permalink to &quot;拆分粒度原则&quot;">​</a></h3><ul><li>团队规模：2 Pizza Team（6-8人）负责一个服务</li><li>独立演进：每个服务可独立部署和升级</li><li>数据私有：服务间通过API交互，不共享数据库</li></ul><h2 id="监控与链路追踪" tabindex="-1">监控与链路追踪 <a class="header-anchor" href="#监控与链路追踪" aria-label="Permalink to &quot;监控与链路追踪&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>监控体系：</span></span>
<span class="line"><span>├── 基础设施监控：Prometheus + Grafana</span></span>
<span class="line"><span>├── 应用监控：SkyWalking / Jaeger</span></span>
<span class="line"><span>├── 日志收集：ELK / Loki</span></span>
<span class="line"><span>└── 告警：AlertManager + 钉钉/邮件</span></span></code></pre></div><h2 id="架构演进路线" tabindex="-1">架构演进路线 <a class="header-anchor" href="#架构演进路线" aria-label="Permalink to &quot;架构演进路线&quot;">​</a></h2><ol><li><strong>单体架构</strong>：所有功能在一个应用中，适合小团队</li><li><strong>垂直拆分</strong>：按业务拆分为多个应用</li><li><strong>服务化</strong>：引入服务注册发现、配置中心、熔断降级</li><li><strong>微服务</strong>：领域驱动设计、容器化部署（K8s）</li></ol>`,17)])])}const b=t(n,[["render",l]]);export{u as __pageData,b as default};
